svg.script:
(function () {
  var KEY = "generic";
  var SCALE = 0.6;
  var GATE_PINS = {"gate-Not":{"in1":[-60,0],"out":[80,0]},"gate-And":{"in1":[-62,-23],"in2":[-62,23],"out":[66,0]},"gate-Or":{"in1":[-58,-23],"in2":[-58,23],"out":[80,0]},"gate-AND3way":{"in1":[-62,-27],"in2":[-62,0],"in3":[-62,27],"out":[66,0]},"gate-OR4way":{"in1":[-60.326107,-30],"in2":[-59.462559,-9.9898129],"in3":[-59.919762,10.020376],"in4":[-60.369907,30],"out":[80,0]}};
  var CARD = {"inputInt1":[175,188],"inputInt2":[175,388],"inputInt3":[300,80],"outputInt":[800,288]};
  var TYPES = {"not-c":"gate-Not","not-in1":"gate-Not","not-in2":"gate-Not","and-m1":"gate-AND3way","and-m2":"gate-AND3way","and-m3":"gate-AND3way","and-m4":"gate-AND3way","or-final":"gate-OR4way"};
  var NS = "http://www.w3.org/2000/svg";
  function svg() { return document.querySelector("svg"); }
  function rootInv() { var s = svg(); try { return s.getScreenCTM().inverse(); } catch (e) { return null; } }
  // element-local (x,y) -> root svg coords (handles Inkscape transforms)
  function toRoot(x, y, el) {
    var s = svg(); var pt = s.createSVGPoint(); pt.x = x; pt.y = y;
    var m; try { m = el.getScreenCTM(); } catch (e) { m = null; }
    if (!m) return [x, y];
    var p = pt.matrixTransform(m); var r = rootInv();
    if (r) p = p.matrixTransform(r);
    return [p.x, p.y];
  }
  function dotCenter(id) {
    var r = document.querySelector('[data-mux-comp][data-id="' + id + '"]');
    if (!r) return null;
    var bb; try { bb = r.getBBox(); } catch (e) { return null; }
    return toRoot(bb.x + bb.width / 2, bb.y + bb.height / 2, r);
  }
  // every pin's current position (from the gate dots + the fixed card pins)
  function pinTargets() {
    var out = [];
    for (var id in TYPES) {
      var c = dotCenter(id); if (!c) continue;
      var pins = GATE_PINS[TYPES[id]] || {};
      for (var p in pins) out.push({ ref: id + "." + p, x: c[0] + pins[p][0] * SCALE, y: c[1] + pins[p][1] * SCALE });
    }
    for (var cp in CARD) out.push({ ref: "task-card-1." + cp, x: CARD[cp][0], y: CARD[cp][1] });
    return out;
  }
  function nearest(x, y, targets) {
    var best = null, bd = Infinity;
    for (var i = 0; i < targets.length; i++) {
      var dx = targets[i].x - x, dy = targets[i].y - y, d = dx * dx + dy * dy;
      if (d < bd) { bd = d; best = targets[i]; }
    }
    return best;
  }
  // the two END points of a wire element, in root coords
  function endpoints(w) {
    var tag = w.tagName.toLowerCase();
    if (tag === "polyline" || tag === "polygon") {
      var pts = w.points; if (!pts || !pts.numberOfItems) return null;
      var a = pts.getItem(0), b = pts.getItem(pts.numberOfItems - 1);
      return [toRoot(a.x, a.y, w), toRoot(b.x, b.y, w)];
    }
    if (tag === "line") return [toRoot(+w.getAttribute("x1"), +w.getAttribute("y1"), w), toRoot(+w.getAttribute("x2"), +w.getAttribute("y2"), w)];
    if (tag === "path") { var L = w.getTotalLength(); var a = w.getPointAtLength(0), b = w.getPointAtLength(L); return [toRoot(a.x, a.y, w), toRoot(b.x, b.y, w)]; }
    return null;
  }
  function deriveConnections() {
    var targets = pinTargets(); var conns = [];
    var wires = document.querySelectorAll("[data-mux-wire]");
    for (var i = 0; i < wires.length; i++) {
      var e = endpoints(wires[i]); if (!e) continue;
      var a = nearest(e[0][0], e[0][1], targets), b = nearest(e[1][0], e[1][1], targets);
      if (a && b && a.ref !== b.ref) conns.push([a.ref, b.ref]);
    }
    return conns;
  }
  function collect() {
    var comps = [];
    for (var id in TYPES) { var c = dotCenter(id); if (c) comps.push({ id: id, x: c[0], y: c[1] }); }
    return { key: KEY, components: comps, connections: deriveConnections() };
  }
  function send() { try { if (window.parent && window.parent !== window) window.parent.postMessage({ __muxSolutionLayout: true, payload: collect() }, "*"); } catch (e) {} }
  function boot() { send(); setTimeout(send, 120); setTimeout(send, 500); }
  if (document.readyState === "loading") window.addEventListener("DOMContentLoaded", boot); else boot();
  window.addEventListener("load", send);
})();
